Rule.Source:
  import sailpoint.api.Workflower;
  import sailpoint.tools.Util;
  import sailpoint.object.Filter;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.WorkItem;
  import sailpoint.object.WorkItem.State;

  QueryOptions ops = new QueryOptions();
  ops.setCloneResults(true);

  ops.addFilter(Filter.like("description", "Failed Workflow Alert", Filter.MatchMode.START));

  Iterator itr = context.search(WorkItem.class, ops, "id");

  while(itr.hasNext()){

    String comment = "Auto-Completed By Rule";
    String workItemId = (String) itr.next()[0];
    WorkItem workItem = context.getObjectById(WorkItem.class, workItemId);
    if(workItem == null) continue; 
    workItem.setAttribute("comments", comment);
    workItem.setCompletionComments(comment);
    workItem.setCompleter("Rule");
    workItem.setState(WorkItem.State.Finished);

    context.startTransaction();
    context.saveObject(workItem);
    context.commitTransaction();

    Workflower workflower = new Workflower(context); 
    workflower.finish(workItem);

  }
  
  Util.flushIterator(itr);

  return "Rule Executed";
